class Solution:
    def uniformArray(self, nums1):
        n = len(nums1)
        for T in (0, 1):
            ok = True
            for i in range(n):
                if nums1[i] % 2 == T:
                    continue
                found = False
                for j in range(n):
                    if j == i:
                        continue
                    if (nums1[i] % 2) ^ (nums1[j] % 2) == T:
                        found = True
                        break
                if not found:
                    ok = False
                    break
            if ok:
                return True
        return False

